import { renderStudyInviteSms, renderStudyReminderSms } from '../study-sms-templates';

export default function law(): void {
  const a = renderStudyInviteSms({
    studyTitle: 'Pilot',
    studyId: 'p1',
    actionUrl: 'https://x.example/y',
    consentVersion: 'v2',
  });
  if (!a.includes('Pilot') || !a.includes('p1') || !a.includes('v2')) {
    throw new Error('invite sms');
  }
  const b = renderStudyReminderSms({
    studyTitle: 'Pilot',
    studyId: 'p1',
    actionUrl: 'https://x.example/y',
  });
  if (!b.toLowerCase().includes('reminder')) throw new Error('reminder sms');
}
